// FORWARD PASS: compute prediction
input = [0.5, 0.8, 0.2]          // input features
hidden = relu(W1 @ input + b1)   // apply weights, bias, activation
output = softmax(W2 @ hidden + b2) // final prediction probabilities

// LOSS CALCULATION: how wrong are we?
loss = cross_entropy(output, true_label)
// If true_label = class_2 and we predicted class_2 with 0.1 probability → high loss

// BACKWARD PASS (backpropagation): compute gradients
gradients = compute_gradients(loss)
// Chain rule traces error back through every layer

// WEIGHT UPDATE (gradient descent):
W1 = W1 - learning_rate * gradients['W1']  // nudge weights toward better predictions
W2 = W2 - learning_rate * gradients['W2']

// Repeat millions of times → network gets accurate

// Core update equation:
// new_weight = old_weight - learning_rate * gradient

learning_rate = 0.01

// If gradient = +5 (loss increases when weight increases):
new_weight = 0.5 - 0.01 * 5  // = 0.45 (step downhill)

// If gradient = -3 (loss decreases when weight increases):
new_weight = 0.5 - 0.01 * (-3)  // = 0.53 (step in positive direction)

// Learning rate too high → overshoots the minimum, diverges
// Learning rate too low → takes forever to converge

