// === INDEXING PHASE (done once, offline) ===

// 1. Load documents
documents = load_pdfs("company_knowledge_base/")  // thousands of docs

// 2. Chunk documents
chunks = split_into_chunks(documents, chunk_size=512, overlap=50)

// 3. Embed each chunk into a vector
embedder = OpenAIEmbeddings()
vectors = embedder.embed(chunks)  // [0.23, -0.14, 0.87, ...] per chunk

// 4. Store in vector database
vector_db = Chroma()
vector_db.add(chunks, vectors)

// === QUERY PHASE (done at inference time) ===

// 5. Embed the user's question
query = "What is our refund policy for digital products?"
query_vector = embedder.embed(query)

// 6. Retrieve the most similar chunks
top_chunks = vector_db.similarity_search(query_vector, k=5)

// 7. Augment the prompt with retrieved context
prompt = f"""Use the following documents to answer the question.
Documents: {top_chunks}
Question: {query}
Answer:"""

// 8. Generate grounded answer
answer = llm.generate(prompt)

